import{_ as e,o as a,c as n,ag as s}from"./chunks/framework.ePeAWSvT.js";const h=JSON.parse('{"title":"Settings & Personalization","description":"","frontmatter":{},"headers":[],"relativePath":"guide/settings.md","filePath":"guide/settings.md"}'),r={name:"guide/settings.md"};function o(i,t,d,l,p,g){return a(),n("div",null,[...t[0]||(t[0]=[s(`<h1 id="settings-personalization" tabindex="-1">Settings &amp; Personalization <a class="header-anchor" href="#settings-personalization" aria-label="Permalink to &quot;Settings &amp; Personalization&quot;">​</a></h1><h2 id="preferences-panel-pref" tabindex="-1">Preferences Panel (PREF) <a class="header-anchor" href="#preferences-panel-pref" aria-label="Permalink to &quot;Preferences Panel (PREF)&quot;">​</a></h2><p>Open with: <code>PREF GO</code></p><h3 id="display-density" tabindex="-1">Display Density <a class="header-anchor" href="#display-density" aria-label="Permalink to &quot;Display Density&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Setting</th><th>Row Height</th><th>Font Size</th><th>Best For</th></tr></thead><tbody><tr><td><strong>Comfortable</strong></td><td>22px</td><td>13px</td><td>Easier reading, larger screens</td></tr><tr><td><strong>Default</strong></td><td>20px</td><td>12px</td><td>Balanced (recommended)</td></tr><tr><td><strong>Compact</strong></td><td>17px</td><td>11px</td><td>Maximum density, Bloomberg-style</td></tr></tbody></table><p>Changes persist to <code>localStorage</code>.</p><h3 id="layout-mode" tabindex="-1">Layout Mode <a class="header-anchor" href="#layout-mode" aria-label="Permalink to &quot;Layout Mode&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Mode</th><th>Description</th></tr></thead><tbody><tr><td><strong>Tile</strong></td><td>Grid of resizable panes (default)</td></tr><tr><td><strong>Tab</strong></td><td>Tabbed panes in a single region</td></tr><tr><td><strong>Stack</strong></td><td>Vertically stacked panes</td></tr></tbody></table><h3 id="streaming-mode" tabindex="-1">Streaming Mode <a class="header-anchor" href="#streaming-mode" aria-label="Permalink to &quot;Streaming Mode&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Toggle</th><th>Effect</th></tr></thead><tbody><tr><td><strong>Live Mode ON</strong></td><td>Increases streaming rate, fills panels with more data</td></tr><tr><td><strong>High Density ON</strong></td><td>Reduces row padding, shows more rows per panel</td></tr></tbody></table><h2 id="workspace-save-restore" tabindex="-1">Workspace Save/Restore <a class="header-anchor" href="#workspace-save-restore" aria-label="Permalink to &quot;Workspace Save/Restore&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes tokyo-night tokyo-night vp-code" tabindex="0"><code><span class="line"><span>WS myname GO          → Save current state as &quot;myname&quot; (or load if exists)</span></span>
<span class="line"><span>WS DEL myname GO      → Delete workspace</span></span>
<span class="line"><span>WS GO                 → Open workspace manager (list all)</span></span>
<span class="line"><span>WS:MARKET-WALL GO     → Load preset: 8-pane market wall</span></span>
<span class="line"><span>WS:NEWSROOM GO        → Load preset: newsroom layout</span></span>
<span class="line"><span>WS:RESEARCH GO        → Load preset: research layout</span></span>
<span class="line"><span>WS:TRADING GO         → Load preset: trading layout</span></span></code></pre></div><p><strong>What a workspace saves:</strong></p><ul><li>Full pane docking tree (splits, tabs, sizes)</li><li>Each panel&#39;s active mnemonic, security, timeframe</li><li>Navigation history per panel</li><li>Command history per panel</li><li>Pin strip items</li><li>Dock layout settings</li></ul><h2 id="keyboard-mapping-keymap" tabindex="-1">Keyboard Mapping (KEYMAP) <a class="header-anchor" href="#keyboard-mapping-keymap" aria-label="Permalink to &quot;Keyboard Mapping (KEYMAP)&quot;">​</a></h2><p>Open with: <code>KEYMAP GO</code></p><p>View and save keyboard binding profiles. Current bindings are shown in a table.<br> Click <strong>SAVE</strong> to persist profile. Click <strong>RESET</strong> to restore defaults.</p><h2 id="export-settings" tabindex="-1">Export Settings <a class="header-anchor" href="#export-settings" aria-label="Permalink to &quot;Export Settings&quot;">​</a></h2><p>Open with: <code>EXP GO</code> or <code>EXPCTR GO</code></p><ul><li>Panel snapshot exports (JSON) via <strong>GRAB GO</strong></li><li>Report builder via <strong>RPT GO</strong></li><li>Clip library via <strong>CLIP GO</strong></li><li>All exports are logged in the audit trail (AUD)</li></ul><h2 id="admin-entitlements" tabindex="-1">Admin &amp; Entitlements <a class="header-anchor" href="#admin-entitlements" aria-label="Permalink to &quot;Admin &amp; Entitlements&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Function</th><th>Purpose</th></tr></thead><tbody><tr><td><strong>ENT GO</strong></td><td>View and manage entitlement matrix</td></tr><tr><td><strong>COMP GO</strong></td><td>Compliance lock modes (normal / restricted / frozen)</td></tr><tr><td><strong>POL GO</strong></td><td>Policy rules engine (allow/block actions by role)</td></tr><tr><td><strong>POLICY GO</strong></td><td>Full policy rules block/allow interface</td></tr><tr><td><strong>ROLE GO</strong></td><td>Roles and permissions assignment</td></tr><tr><td><strong>ADMIN GO</strong></td><td>Admin console (users, roles, entitlements, policies)</td></tr><tr><td><strong>AUD GO</strong></td><td>Command audit log</td></tr><tr><td><strong>AUDIT GO</strong></td><td>Full audit trail with replay</td></tr></tbody></table>`,22)])])}const m=e(r,[["render",o]]);export{h as __pageData,m as default};
